// ============================================================
//  PRIMORDIAL SOUP
//  Gray-Scott reaction-diffusion with a self-avoiding
//  pheromone memory field.
//
//  R = chemical U (food)      kernel delivers laplacian(U)
//  G = chemical V (organism)  kernel delivers laplacian(V)
//  B = glow trail             kernel delivers gaussian-blur(V)
//
//  The twist: organisms die faster inside their own old
//  glowing trail (TRAIL_AVOID), so colonies migrate, carve
//  labyrinths, and refuse to backfill explored space.
//  Set TRAIL_AVOID to 0 for classic Gray-Scott.
//
//  Regimes to dial in with FEED / KILL:
//    0.0367 / 0.062  ->  dividing cells (default)
//    0.030  / 0.062  ->  solitons
//    0.055  / 0.062  ->  coral growth
//    0.026  / 0.058  ->  pulsing chaos
//
//  How to seed life: wait until the screen turns red (the
//  food field filling in), then paint a few small blobs.
//  Life needs structure -- a fully random canvas collapses!
// ============================================================

const FEED: f32 = 0.0367; @variable 0.0 0.1
const KILL: f32 = 0.062; @variable 0.03 0.075
const DIFFUSE_U: f32 = 1.0; @variable 0.2 1.4
const DIFFUSE_V: f32 = 0.5; @variable 0.1 0.7
const SPEED: f32 = 1.0; @variable 0.2 1.8
const TRAIL_AVOID: f32 = 0.004; @variable 0.0 0.02
const GLOW_GAIN: f32 = 1.6; @variable 0.0 4.0
const GLOW_FADE: f32 = 0.985; @variable 0.8 0.999

// Stochastic-rounding dither: the canvas only stores 8 bits per
// channel, which would freeze the tiny chemical gradients this
// system lives on. A +-0.5/255 dither makes sub-quantum updates
// survive on average, keeping the chemistry alive.
fn hash01(p: vec3<f32>) -> f32 {
  return fract(sin(dot(p, vec3<f32>(127.1, 311.7, 74.7))) * 43758.5453123);
}

fn activation(x: f32) -> f32 {
  let u = activationContext.cellState.r;
  let v = activationContext.cellState.g;
  let trail = activationContext.cellState.b;
  let reaction = u * v * v;

  var result: f32;
  if (activationContext.channel == 0u) {
    // U: diffuses (x = laplacian of U), eaten by V, refilled by FEED
    result = u + (DIFFUSE_U * x - reaction + FEED * (1.0 - u)) * SPEED;
  } else if (activationContext.channel == 1u) {
    // V: diffuses (x = laplacian of V), grows by eating U, dies at
    // KILL rate -- faster inside its own glowing trail
    let kill = KILL + TRAIL_AVOID * trail;
    result = v + (DIFFUSE_V * x + reaction - (FEED + kill) * v) * SPEED;
  } else {
    // Trail: x = gaussian-blurred V. Remembers where life has been.
    result = max(trail * GLOW_FADE - 0.002, x * GLOW_GAIN);
  }

  let dither = hash01(vec3<f32>(
    f32(activationContext.gid.x),
    f32(activationContext.gid.y),
    activationContext.timestep + f32(activationContext.channel) * 17.0
  )) - 0.5;

  return result + dither / 255.0;
}
